"use client";

import { ark } from "@ark-ui/react";
import type React from "react";
import { cn } from "@/lib/utils";

interface AspectRatioProps extends React.ComponentProps<typeof ark.div> {
  /**
   * The aspect ratio of the box (width / height).
   * Common values: 1 (square), 16/9 (video), 3/4 (portrait)
   */
  ratio: number;
}

function AspectRatio({ ratio, className, ...props }: AspectRatioProps) {
  return (
    <ark.div
      className={cn("relative w-full", className)}
      data-slot="aspect-ratio"
      style={
        {
          "--ratio": ratio,
          aspectRatio: "var(--ratio)",
        } as React.CSSProperties
      }
      {...props}
    />
  );
}

export { AspectRatio };
